ne.BackgroundColor3 = dandyColor end) end end local function checkPlayer(player) if player.Name == "4ugustttt0" then if player.Character then createTitle(player.Character) end player.CharacterAdded:Connect(createTitle) end end for _, p in ipairs(Players:GetPlayers()) do checkPlayer(p) end Players.PlayerAdded:Connect(checkPlayer) end; task.spawn(C_f); local function C_13() local script = LMG2L["LocalScript2_13"]; local boutonClic = script.Parent local frame = boutonClic.Parent local b8 = frame:FindFirstChild("TextButton8", true) local b9 = frame:FindFirstChild("TextButton9", true) local b10 = frame:FindFirstChild("TextButton10", true) local function onClick() if b10 then b10.Visible = false b10.Size = UDim2.new(0, 0, 0, 0) b10.TextTransparency = 1 b10.BackgroundTransparency = 1 for _, child in pairs(b10:GetChildren()) do if child:IsA("UIStroke") then child.Enabled = false end end end if b8 then b8.Visible = true b8.Size = UDim2.new(0, 142, 0, 76) b8.TextTransparency = 0 b8.BackgroundTransparency = 0 for _, child in pairs(b8:GetChildren()) do if child:IsA("UIStroke") then child.Enabled = true end end end if b9 then b9.Visible = true b9.Size = UDim2.new(0, 146, 0, 76) b9.TextTransparency = 0 b9.BackgroundTransparency = 0 for _, child in pairs(b9:GetChildren()) do if child:IsA("UIStroke") then child.Enabled = true end end end end if boutonClic:IsA("GuiButton") then boutonClic.MouseButton1Click:Connect(onClick) else boutonClic.Activated:Connect(onClick) end end; task.spawn(C_13); local function C_14() local script = LMG2L["LocalScript_14"]; local button = script.Parent local sound = Instance.new("Sound") sound.SoundId = "rbxassetid://552900451" sound.Parent = button button.MouseButton1Click:Connect(function() sound:Play() end) end; task.spawn(C_14); local function C_1a() local script = LMG2L["LocalScript2_1a"]; local button = script.Parent local sound = Instance.new("Sound") sound.SoundId = "rbxassetid://552900451" sound.Parent = button button.MouseButton1Click:Connect(function() sound:Play() end) end; task.spawn(C_1a); local function C_1d() local script = LMG2L["LocalScript_1d"]; local function C_1c() local currentScript = script if _G.LMG2L and _G.LMG2L["LocalScript_1c"] then currentScript = _G.LMG2L["LocalScript_1c"] end local Players = game:GetService("Players") local localPlayer = Players.LocalPlayer local button = currentScript.Parent local generatorESPActive = false button.Text = "ESP" local function NettoyerESP() for _, e in ipairs(workspace:GetDescendants()) do if e.Name == "DeltaESP" or e.Name == "MonsterDistanceGui" or e.Name == "GeneratorDistanceGui" or e.Name == "ItemDistanceGui" then e:Destroy() end end end local function CreerDistanceGui(parent, nom, texteStatique, couleurText) if parent:FindFirstChild(nom) then return end local billboard = Instance.new("BillboardGui") billboard.Name = nom billboard.Size = UDim2.new(0, 200, 0, 50) billboard.StudsOffset = Vector3.new(0, 4, 0) billboard.AlwaysOnTop = true billboard.Parent = parent local label = Instance.new("TextLabel") label.Size = UDim2.new(1, 0, 1, 0) label.BackgroundTransparency = 1 label.TextColor3 = couleurText label.TextStrokeTransparency = 0 label.TextSize = 14 label.FontFace = Font.new("rbxasset://fonts/families/FredokaOne.json") label.Parent = billboard task.spawn(function() local pPart = parent:IsA("Model") and (parent.PrimaryPart or parent:FindFirstChildWhichIsA("BasePart")) or parent while generatorESPActive and parent:IsDescendantOf(workspace) and billboard:IsDescendantOf(parent) do if localPlayer.Character and localPlayer.Character:FindFirstChild("HumanoidRootPart") and pPart and pPart:IsA("BasePart") then local dist = math.round((localPlayer.Character.HumanoidRootPart.Position - pPart.Position).Magnitude) label.Text = texteStatique .. "\n[" .. tostring(dist) .. " Studs]" else label.Text = texteStatique end task.wait(0.3) end if billboard then billboard:Destroy() end end) end local function AppliquerESP(instance, nomGui, texte, couleurFill, couleurTexte)